using UnityEngine.SceneManagement;

public class ScoreManager : MonoBehaviour
{
    public TextMeshProUGUI scoreText;

    int score = 0;

    void Start()
    {
        scoreText.text = "Score: 0";

        Time.timeScale = 1f;
    }

    public void AddScore()
    {
        score++;

