﻿using UnityEngine;
using System.Collections.Generic;

/// <summary>
/// This class allows us to create multiple instances of a prefabs and reuse them.
/// It allows us to avoid the cost of destroying and creating objects.
/// </summary>
public class Pooler
{
	protected Stack<GameObject> m_FreeInstances = new Stack<GameObject>();
	protected GameObject m_Original;

	public Pooler(GameObject original, int initialSize)
	{
		m_Original = original;
		m_FreeInstances = new Stack<GameObject>(initialSize);

		for (int i = 0; i < initialSize; ++i)
		{
			GameObject obj = Object.Instantiate(original);
			obj.SetActive(false);
            m_FreeInstances.Push(obj);
		}
	}

	public GameObject Get()
	{
		return Get(Vector3.zero, Quaternion.identity);
	}

	public GameObject Get(Vector3 pos, Quaternion quat)
	{
	    GameObject ret = m_FreeInstances.Count > 0 ? m_FreeInstances.Pop() : Object.Instantiate(m_Original);

		ret.SetActive(true);
		ret.transform.position = pos;
		ret.transform.rotation = quat;

		return ret;
	}

	public void Free(GameObject obj)
	{
		obj.transform.SetParent(null);
		obj.SetActive(false);
		m_FreeInstances.Push(obj);
	}
}

﻿using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Audio;

//This is a helper script that allow to assign an object in a bundle it's mixer output to the main mixer
//as if we assign it in editor, a copy of the mixer will be added to the bundle and won't use the main mixer
public class AssignOutputChannel : MonoBehaviour
{
    public string mixerGroup;

    private void Awake()
    {
        AudioSource source = GetComponent<AudioSource>();

        if (source == null)
        {
            Debug.LogError("That object don't have any audio source, can't change it's output", gameObject);
            Destroy(this);
            return;
        }

        AudioMixerGroup[] groups = MusicPlayer.instance.mixer.FindMatchingGroups(mixerGroup);

        if(groups.Length == 0)
        {
            Debug.LogErrorFormat(gameObject, "Could not find any group called {0}", mixerGroup);
        }

        for(int i = 0; i < groups.Length; ++i)
        {
            if (groups[i].name == mixerGroup)
            {
                source.outputAudioMixerGroup = groups[i];
                break;
            }
        }
    }
}

